+    Trigger {
+        /// Stable item key.
+        item_key: Key,
+
+        /// Associated content element id.
+        content_id: String,
+    },
+
+    /// Dropdown content for a trigger.
+    Content {
+        /// Stable item key.
+        item_key: Key,
+    },
